import json
from typing import Dict, Any
from llama_stack_client import ToolResponse

def validate_tool_pii_schema(tool_response: ToolResponse) -> Dict[str, Any]:
    violations = []

    # Parse tool response per Llama Stack schema
    try:
        data = json.loads(tool_response.content)

        # Check PII patterns in expected fields
        pii_patterns = [
            r'\b\d{3}-\d{2}-\d{4}\b',  # SSN
            r'\b\d{3}-\d{3}-\d{4}\b',  # Phone
            r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b'  # Email
        ]

        for pattern in pii_patterns:
            matches = re.findall(pattern, json.dumps(data))
            if matches:
                violations.append({'pattern': pattern, 'matches': matches})

    except json.JSONDecodeError:
        violations.append({'error': 'Invalid JSON schema'})

    return {'pii_violations': violations, 'is_clean': len(violations) == 0}
