class ContextualPIIFilter:
    def __init__(self):
        self.benign_patterns = {
            'demo_phone': r'555-\d{4}',
            'test_email': r'example@demo\.com',
            'fixture_ssn': r'123-45-6789'
        }

    def should_redact(self, content: str, context: str) -> bool:
        context_lower = context.lower()

        # Whitelist demo/fixture data
        for pattern_name, pattern in self.benign_patterns.items():
            if re.search(pattern, content) and context_lower in ['demo', 'test', 'fixture']:
                return False

        # Standard PII detection
        return bool(re.search(r'\b\d{3}-\d{2}-\d{4}\b', content))

# Integration with Llama Stack
agent = LlamaStackAgent()
filter = ContextualPIIFilter()

